import { test, expect } from '@playwright/test';

test('verify header navigation links', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('http://localhost:3002/');

  // Verify brand link (Home)
  const brandLink = page.getByRole('link', { name: 'okwasniewski' });
  await expect(brandLink).toHaveAttribute('href', '/');
  await brandLink.click();
  await expect(page).toHaveURL('http://localhost:3002/');

  // Verify Blog link
  const blogLink = page.getByRole('link', { name: 'blog' });
  await expect(blogLink).toHaveAttribute('href', '/blog');
  await blogLink.click();
  await expect(page).toHaveURL(/.*\/blog/);

  // Verify Portfolio link
  const portfolioLink = page.getByRole('link', { name: 'portfolio' });
  await expect(portfolioLink).toHaveAttribute('href', '/portfolio');
  await portfolioLink.click();
  await expect(page).toHaveURL(/.*\/portfolio/);

  // Verify Videos link
  const videosLink = page.getByRole('link', { name: 'videos' });
  await expect(videosLink).toHaveAttribute('href', '/videos');
  await videosLink.click();
  await expect(page).toHaveURL(/.*\/videos/);

  // Verify Contact link (FAIL on homepage)
  await page.goto('http://localhost:3002/');
  const contactElement = page.getByText('contact');
  const tagName = await contactElement.evaluate(el => el.tagName);
  if (tagName !== 'A') {
    console.error('Contact item is not a link on the homepage');
  }
});
